css:
:host { display: block; }
.faq { padding: 4rem 2rem; max-width: 720px; margin: 0 auto; }
h2 { font-size: 2rem; color: white; text-align: center; margin: 0 0 2.5rem; }
.item { border-bottom: 1px solid #2a2a2e; }
.question { display: flex; align-items: center; justify-content: space-between; width: 100%; padding: 1.25rem 0; background: none; border: none; color: white; font-size: 1rem; cursor: pointer; text-align: left; font-family: var(--font-body, system-ui, sans-serif); }
.question:hover { color: var(--primary); }
.chevron { transition: transform 0.25s ease; flex-shrink: 0; margin-left: 1rem; }
.item.open .chevron { transform: rotate(180deg); }
.answer { padding: 0 0 1.25rem; color: #adadb0; line-height: 1.7; font-size: 0.95rem; }
.answer[hidden] { display: none; }

js:
root.querySelectorAll('.question').forEach(btn => {
  btn.addEventListener('click', () => {
    const item = btn.closest('.item');
    const answer = item.querySelector('.answer');
    const wasOpen = !answer.hidden;
    // Close all
    root.querySelectorAll('.item').forEach(i => {
      i.classList.remove('open');
      i.querySelector('.answer').hidden = true;
    });
    // Toggle clicked
    if (!wasOpen) {
      item.classList.add('open');
      answer.hidden = false;
    }
  });
});
